qry:select.qry:xquery:
for $r in sql(' SELECT CAR.oi_carpeta, CAR.f_carpeta, CAR.f_prescripcion, CAR.d_carpeta, CAR.c_carpeta, CAR.c_criticidad, CAR.l_cerrado as l_cerrado, CAR.f_egreso, EST.d_estado as oi_estado_carpeta, SUJ_CAR.c_sujeto, SUJ_CAR.d_sujeto, UBI_CAR.d_ubicacion, EMP_CAR.d_empresa, SUJ_PAR.d_sujeto as d_sujeto_rol, ROL.d_rol, MON.f_monto, MON.n_monto, MON.l_facturable, MON.n_monto_fact, PRE.n_porcentaje_prev, PRE.n_monto_prev, PRE.n_porcentaje_cos, PRE.n_monto_cos, CAU.d_causa, GJURIS.c_grupo_jur, GJURIS.d_grupo_jur, JURIS.c_jurisdiccion, JURIS.d_jurisdiccion, TC.c_tipo_carpeta, TC.d_tipo_carpeta, OBJREC.c_objeto_reclamo, OBJREC.d_objeto_reclamo
FROM LEG01_CARPETAS as CAR, LEG42_TIPO_CARPETA as TC, LEG01_PARTES as PAR, LEG01_OBJ_CARPETA as OBJ, LEG32_OBJ_RECLAMOS as OBJREC, LEG30_CAUSAS as CAU, LEG02_MONTOS(l_vigente=\'1\') as MON, LEG02_PREVISIONES as PRE, LEG31_ESTADOS as EST, LEG40_SUJETOS as SUJ_CAR, ORG03_UBICACIONES as UBI_CAR, ORG03_EMPRESAS as EMP_CAR, LEG40_SUJETOS as SUJ_PAR, LEG33_ROL as ROL, LEG01_RADICACION (l_vigente=\'1\') as RAD, LEG48_GRUPO_JUR as GJURIS, LEG48_JURISDICCION as JURIS
JOIN CAR.oi_empresa INNER EMP_CAR.oi_empresa, CAR.oi_estado_carpeta INNER EST.oi_estado, CAR.oi_sujeto INNER SUJ_CAR.oi_sujeto, CAR.oi_ubicacion LEFT OUTER UBI_CAR.oi_ubicacion, PAR.oi_carpeta INNER CAR.oi_carpeta, PAR.oi_sujeto INNER SUJ_PAR.oi_sujeto, PAR.oi_rol INNER ROL.oi_rol, PAR.oi_parte LEFT OUTER OBJ.oi_parte, OBJ.oi_causa LEFT OUTER CAU.oi_causa, OBJ.oi_objeto_reclamo LEFT OUTER OBJREC.oi_objeto_reclamo, CAR.oi_tipo_carpeta LEFT OUTER TC.oi_tipo_carpeta, OBJ.oi_obj_rec_carpeta LEFT OUTER MON.oi_obj_rec_carpeta, MON.oi_monto LEFT OUTER PRE.oi_monto, CAR.oi_carpeta LEFT OUTER RAD.oi_carpeta, RAD.oi_jurisdiccion LEFT OUTER JURIS.oi_jurisdiccion, JURIS.oi_grupo_jur LEFT OUTER GJURIS.oi_grupo_jur
WHERE CAR.oi_estado_carpeta != 11 AND OBJ.l_inactivo != 1 AND CAR.oi_carpeta IN ({%=$PARAM/@oi_carpeta%}) {%?(#FILTRO:@nrosWhere!='') {% AND ({%=#FILTRO:@nrosWhere%}) %} {% %} %} {%?(#FILTRO:@codsWhere!='') {% AND ({%=#FILTRO:@codsWhere%}) %} {% %} %} {%?(#FILTRO:@d_carpeta!='') {% AND CONTAIN(CAR.d_carpeta, \'{%=#FILTRO:@d_carpeta%}\') %} {% %} %}
{%?(#FILTRO:@f_carpeta_d!='') {% AND CAR.f_carpeta >= {#FILTRO:@f_carpeta_d} %} {% %} %} {%?(#FILTRO:@f_carpeta_h!='') {% AND CAR.f_carpeta < {Datetime(Number(Datetime(#FILTRO:@f_carpeta_h))+1)} %} {% %} %}
{%?(#FILTRO:@oi_estado_carpeta!='') {% AND CAR.oi_estado_carpeta = {#FILTRO:@oi_estado_carpeta} %} {% %} %} {%?(#FILTRO:@cerrado='2') {% AND CAR.l_cerrado = 1 %} {% %} %} {%?(#FILTRO:@cerrado='3') {% AND CAR.l_cerrado = 0 %} {% %} %}
{%?(#FILTRO:@oi_ubicacion!='') {% AND CAR.oi_ubicacion = {#FILTRO:@oi_ubicacion} %} {% %} %} {%?(#FILTRO:@oi_sujeto!='') {% AND CAR.oi_sujeto = {#FILTRO:@oi_sujeto} %} {% %} %} {%?(#FILTRO:@oi_empresa!='') {% AND CAR.oi_empresa = {#FILTRO:@oi_empresa} %} {% %} %} {%?(#FILTRO:@oi_rol_parte!='' OR #FILTRO:@oi_sujeto_parte!='') {% AND CAR.oi_carpeta = PAR.oi_carpeta %} {% %} %} {%?(#FILTRO:@oi_rol_parte!='') {% AND PAR.oi_rol = {#FILTRO:@oi_rol_parte} %} {% %} %} {%?(#FILTRO:@oi_sujeto_parte!='') {% AND PAR.oi_sujeto = {#FILTRO:@oi_sujeto_parte} %} {% %} %} {%?(#FILTRO:@oi_grupo_jur!='') {% AND GJURIS.oi_grupo_jur = {#FILTRO:@oi_grupo_jur} %} {% %} %} {%?(#FILTRO:@oi_jurisdiccion!='') {% AND JURIS.oi_jurisdiccion = {#FILTRO:@oi_jurisdiccion} %} {% %} %}
{%?(#FILTRO:@TIPOSCARPETAS_IDs!='') {% AND CAR.oi_tipo_carpeta {%=#FILTRO:@TIPOSCARPETAS_IDs%} %} {% %} %}
ORDER BY oi_carpeta asc')/ROWS/ROW
